// Get both scraped pages
const yourHtml = $input.first().json.data || $input.first().json.body || $input.first().json || '';
const config = $('2. Set — Extract Form Fields').item.json;

// Clean HTML — remove scripts, styles, keep text
function cleanHtml(html) {
  if (typeof html !== 'string') html = JSON.stringify(html);
  return html
    .replace(/<script[\s\S]*?<\/script>/gi, '')
    .replace(/<style[\s\S]*?<\/style>/gi, '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .substring(0, 8000);
}

const cleanedYours = cleanHtml(yourHtml);

return [{
  json: {
    yourPageText: cleanedYours,
    yourUrl: config.yourUrl,
    competitorUrl: config.competitorUrl,
    targetKeyword: config.targetKeyword,
    businessName: config.businessName,
    runDate: config.runDate
  }
}];

// Get competitor scraped page
const competitorHtml = $input.first().json.data || $input.first().json.body || $input.first().json || '';
const yourPageData = $('5. Code — Clean Your Page HTML').item.json;

// Clean HTML — remove scripts, styles, keep text
function cleanHtml(html) {
  if (typeof html !== 'string') html = JSON.stringify(html);
  return html
    .replace(/<script[\s\S]*?<\/script>/gi, '')
    .replace(/<style[\s\S]*?<\/style>/gi, '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .substring(0, 8000);
}

const cleanedCompetitor = cleanHtml(competitorHtml);

return [{
  json: {
    yourPageText: yourPageData.yourPageText,
    competitorPageText: cleanedCompetitor,
    yourUrl: yourPageData.yourUrl,
    competitorUrl: yourPageData.competitorUrl,
    targetKeyword: yourPageData.targetKeyword,
    businessName: yourPageData.businessName,
    runDate: yourPageData.runDate
  }
}];

// Merge both cleaned page texts into one item for AI Agent
const items = $input.all();

// Item 0 = Your page (from Clean Your Page HTML)
// Item 1 = Competitor page (from Clean Competitor Page HTML)
const yourData = items[0]?.json || {};
const competitorData = items[1]?.json || {};

return [{
  json: {
    yourPageText: yourData.yourPageText || 'Could not scrape your page.',
    competitorPageText: competitorData.competitorPageText || 'Could not scrape competitor page.',
    yourUrl: yourData.yourUrl || competitorData.yourUrl,
    competitorUrl: yourData.competitorUrl || competitorData.competitorUrl,
    targetKeyword: yourData.targetKeyword || competitorData.targetKeyword,
    businessName: yourData.businessName || competitorData.businessName,
    runDate: yourData.runDate || competitorData.runDate
  }
}];

